// Agrega os KPIs da semana a partir das abas leads e bookings.
// Decisão de arquitetura: os números são calculados aqui (exatos e auditáveis);
// o LLM só redige o texto. Ver prompts/weekly-report.md
// As datas são comparadas em "hora de parede" de Lisboa: o runner de Code nodes
// do n8n pode correr em UTC, e new Date(a, m, d, ...) usaria esse fuso.
const MS_DIA = 24 * 60 * 60 * 1000;
const FMT_LISBOA = new Intl.DateTimeFormat('pt-PT', {
  timeZone: 'Europe/Lisbon', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit'
});

// "dd/mm/aaaa hh:mm" (registos atuais) ou ISO (linhas antigas) -> ms em escala de parede.
function parseData(s) {
  if (!s) return NaN;
  const m = String(s).match(/^(\d{2})\/(\d{2})\/(\d{4})[ ,]+(\d{2}):(\d{2})/);
  if (m) return Date.UTC(+m[3], +m[2] - 1, +m[1], +m[4], +m[5]);
  const t = Date.parse(s);
  if (Number.isNaN(t)) return NaN;
  return parseData(FMT_LISBOA.format(new Date(t)).replace(',', ''));
}

const agora = parseData(FMT_LISBOA.format(new Date()).replace(',', ''));
const inicioSemana = agora - 7 * MS_DIA;
const inicioAnterior = agora - 14 * MS_DIA;

function noPeriodo(lista, inicio, fim) {
  return lista.filter((r) => {
    const t = parseData(r.timestamp);
    return !Number.isNaN(t) && t >= inicio && t < fim;
  });
}

function contarPor(lista, campo) {
  const out = {};
  for (const r of lista) {
    const k = r[campo] || 'desconhecido';
    out[k] = (out[k] || 0) + 1;
  }
  return out;
}

// alwaysOutputData pode devolver um item vazio quando a aba está vazia — filtrar.
const leads = $('Ler leads').all().map((i) => i.json).filter((r) => r.email);
const bookings = $('Ler bookings').all().map((i) => i.json).filter((r) => r.email);

const leadsSemana = noPeriodo(leads, inicioSemana, agora);
const leadsAnterior = noPeriodo(leads, inicioAnterior, inicioSemana);
const bookingsSemana = noPeriodo(bookings, inicioSemana, agora);
const bookingsAnterior = noPeriodo(bookings, inicioAnterior, inicioSemana);

const fmtDia = new Intl.DateTimeFormat('pt-PT', {
  day: 'numeric', month: 'short', year: 'numeric', timeZone: 'Europe/Lisbon'
});
// Para exibição usa o relógio real (não a escala de parede auxiliar), com o fuso explícito.
const periodo = fmtDia.format(new Date(Date.now() - 7 * MS_DIA)) + ' - ' + fmtDia.format(new Date());

const taxa = leadsSemana.length
  ? ((bookingsSemana.length / leadsSemana.length) * 100).toFixed(1) + '%'
  : 'n/a';

return [{
  json: {
    kpis: {
      periodo,
      total_leads: leadsSemana.length,
      leads_por_servico: contarPor(leadsSemana, 'servico'),
      leads_por_urgencia: contarPor(leadsSemana, 'urgencia'),
      consultas_marcadas: bookingsSemana.length,
      taxa_conversao: taxa,
      semana_anterior: {
        total_leads: leadsAnterior.length,
        consultas_marcadas: bookingsAnterior.length
      }
    }
  }
}];

// Constrói o pedido Gemini do relatório semanal.
// Prompt documentado em prompts/weekly-report.md
const system = `És analista de marketing da Clínica Vitalis. Escreves o resumo semanal para a
gerência com base em KPIs já calculados. Escreves em português europeu.

Regras:
- Usa APENAS os números fornecidos. Nunca inventes, estimes ou recalcules valores.
- Estrutura: 1 parágrafo com a leitura geral da semana (incluindo comparação com a
  semana anterior) → lista de bullets com os KPIs principais → 1 parágrafo final
  com uma recomendação prática baseada nos dados (ex.: reforçar resposta a leads
  de urgência alta, investir no serviço com mais procura).
- Nos bullets usa hífen (-) no início de cada linha, nunca asteriscos.
- Máximo 180 palavras. Tom profissional e direto, sem jargão.
- Responde só com o texto do email, sem assunto nem saudação inicial.`;

const kpis = $input.first().json.kpis;
const user = 'KPIs da semana:\n' + JSON.stringify(kpis, null, 2);

return [{
  json: {
    periodo: kpis.periodo,
    body: {
      system_instruction: { parts: [{ text: system }] },
      contents: [{ role: 'user', parts: [{ text: user }] }],
      generationConfig: { temperature: 0.4 }
    }
  }
}];

// Extrai o texto do relatório (resposta em texto livre, não JSON).
// >>> EDITAR: substitui pelo email real da "gerência" (ex.: o teu alias +gerencia) <<<
const DESTINATARIO = 'gerencia@example.com';

const resp = $input.first().json;
let text = resp.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
text = text.trim();
if (!text) {
  throw new Error('Resposta vazia do Gemini');
}

const periodo = $('Preparar pedido Gemini').first().json.periodo;

return [{
  json: {
    destinatario: DESTINATARIO,
    assunto: 'Relatório semanal de KPIs - Clínica Vitalis (' + periodo + ')',
    corpo: text
  }
}];

// Linha de log do relatório semanal (só corre após envio com sucesso).
const r = $('Interpretar relatório').first().json;
return [{
  json: {
    timestamp: new Date().toLocaleString('pt-PT', { timeZone: 'Europe/Lisbon', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }).replace(',', ''),
    tipo: 'relatorio',
    destinatario: r.destinatario,
    assunto: r.assunto
  }
}];
